output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?series ?seriesLabel WHERE {
  ?movie wdt:P31 wd:Q11424 ; wdt:P577 ?releaseDate ; wdt:P1433 ?game .
  ?game wdt:P176 wd:Q149947 ; wdt:P752 ?series .
  FILTER(STRSTARTS(STR(?releaseDate) , "1995"))
  OPTIONAL {
    ?series rdfs:label ?seriesLabel .
    FILTER(LANG(?seriesLabel) = "en")
  }
}

args.sparql:
SELECT ?gameSeries ?gameSeriesLabel WHERE {
  ?gameSeries wdt:P31 wd:Q6200762; 
             wdt:P176 wd:Q149947.
  ?movie wdt:P1433 ?gameSeries;
         wdt:P577 ?releaseDate.
  FILTER (STRSTARTS(STR(?releaseDate), "1995"))
  OPTIONAL { ?gameSeries rdfs:label ?gameSeriesLabel. FILTER (LANG(?gameSeriesLabel) = "en") }
}

